        padding-left: 10px !important;
      }

      /* ── Menu export : plus grand pour le tactile ── */
      .export-menu { min-width: 220px; }
      .export-menu .ex-item { padding: 12px 14px; font-size: 14px; }

      /* ── Zone de saisie ── */
      .input-area { padding: 6px 6px; }
      .textarea-wrap textarea {
        font-size: 16px !important;
        min-height: 44px;
        padding: 10px 90px 10px 12px;
