      /* ── Recherche sidebar ── */
      .search-input { font-size: 16px !important; }
      .search-results { max-height: 55vh; }
      .search-result-item { padding: 12px 14px; }

      /* ── Code : header compact ── */
      .code-header { font-size: 11px; padding: 4px 8px; }
      .copy-code-btn { font-size: 11px; padding: 3px 6px; }

      /* ── Home mode ── */
      .main.home-mode h1 { font-size: 1.3em; }
      .main.home-mode .home-subtitle { font-size: 13px; }

      /* ── Profil éditeur : champs plus grands ── */
      .pe-input, .pe-emoji { font-size: 16px !important; min-height: 44px; }
      .pe-textarea { font-size: 16px !important; min-height: 120px; }
      .pe-btn { min-height: 44px; font-size: 14px; }

      /* ── GitHub panel inputs ── */
      #githubPanel input { font-size: 16px !important; min-height: 40px; }
      #githubPanel .btn, #githubPanel button { min-height: 44px; }

      /* ── API Key panel inputs ── */
      #apiKeyPanel input { font-size: 16px !important; min-height: 40px; }

      /* ── Chat items sidebar : plus grands pour le tactile ── */
      .item { padding: 10px 10px; min-height: 44px; }
      .chat-menu-btn { opacity: 1; font-size: 18px; padding: 6px 8px; }
    }

    /* ── Hauteur viewport dynamique (clavier virtuel iOS) ── */
    @supports (height: 100dvh) {
      @media (max-width: 1024px) {
        .app { height: 100dvh; }
        .sidebar { height: 100dvh; }
      }
    }

