        <div id="rightPanel" class="params right-panel" style="right:100px;top:46px;width:380px">
          <div class="right-panel-head">
            <span class="right-panel-title">📖 Profils système</span>
            <button class="icon-btn" id="newProfileBtn" title="Nouveau profil" style="font-size:18px;color:#7baaf7">＋</button>
          </div>
          <div id="activePromptBanner" style="display:none;margin:6px 8px;padding:6px 10px;background:#1e2a3a;border:1px solid #1f6feb44;border-radius:8px;font-size:11px;color:#7baaf7;line-height:1.4">
            <div style="font-weight:600;margin-bottom:3px">✅ Profil actif :</div>
