function save() {
  try {
    // TOUJOURS sérialiser les chats SANS données binaires volumineuses
    // Ceci évite : blocage du thread principal, localStorage saturé, sync GitHub qui explose
    const lightChats = S.chats.map(chat => ({
      ...chat,
      messages: chat.messages.map(m => {
        if (!Array.isArray(m.content)) return m;
        return { ...m, content: m.content.map(b => {
          if ((b.type === 'document' || b.type === 'image') && b.source?.data?.length > 50000) {
            return { type: 'text', text: `[Fichier joint : ${b.title || b.type} — contenu envoyé au modèle, non stocké]` };
          }
          return b;
        })};
      })
    }));
    localStorage.setItem("projects",           JSON.stringify(S.projects));
    localStorage.setItem("profiles",        JSON.stringify(S.profiles));
    localStorage.setItem("activeProfiles",  JSON.stringify(S.activeProfiles || []));
    localStorage.setItem("chats",              JSON.stringify(lightChats));
    localStorage.setItem("activeChat",         S.activeChat    || "");
    localStorage.setItem("activeProject",      S.activeProject || "");
    localStorage.setItem("model",              S.model);
    localStorage.setItem("params",             JSON.stringify(S.params));
    localStorage.setItem("apiKeysByProvider",  JSON.stringify(apiKeysByProvider));
  } catch (e) {
    console.warn('[BrAInShift] ⚠ Sauvegarde échouée:', e.message);
    try {
      localStorage.setItem("activeChat",        S.activeChat    || "");
      localStorage.setItem("model",             S.model);
      localStorage.setItem("params",            JSON.stringify(S.params));
    } catch(e2) {}
  }
}

