function inferProviderFromModel(model) {
  const m = (model || "").toLowerCase();
  if (m.startsWith("claude"))   return "ANTHROPIC";
  if (m.startsWith("gemini"))   return "GOOGLE GEMINI";
  if (m.startsWith("deepseek")) return "DEEPSEEK";
  // Groq models — détection par préfixe de famille ou nom connu
  const GROQ_MODELS = MODEL_GROUPS.find(g => g.label.includes("Groq"))?.models || [];
  if (GROQ_MODELS.includes(model)) return "GROQ";
  return "OPENAI";
}

