    .chat-ctx-menu .ctx-item{
      display:flex;align-items:center;gap:8px;
      padding:8px 14px;color:#c9d0db;cursor:pointer;white-space:nowrap;
    }
    .chat-ctx-menu .ctx-item:hover{background:#ffffff10}
    .chat-ctx-menu .ctx-item.danger{color:#f87171}
    .chat-ctx-menu .ctx-item.danger:hover{background:#f8717115}
    .chat-ctx-menu .ctx-divider{height:1px;background:var(--line);margin:4px 0}
    .chat-ctx-menu .ctx-sub{
      padding:6px 14px 6px 32px;font-size:12px;color:#9ca3af;cursor:pointer;
    }
    .chat-ctx-menu .ctx-sub:hover{background:#ffffff10;color:#e0e0e0}
    .chat-ctx-menu .ctx-sub .proj-dot{
      display:inline-block;width:8px;height:8px;border-radius:50%;margin-right:6px;vertical-align:middle;
    }
    .provider-badge{display:inline-block;font-size:11px;padding:2px 8px;border-radius:20px;margin-bottom:4px;font-weight:600;letter-spacing:.04em}
    .badge-openai{background:#10a37f22;color:#10a37f;border:1px solid #10a37f44}
    .badge-anthropic{background:#c8621a22;color:#c8621a;border:1px solid #c8621a44}
    .badge-deepseek{background:#4a6cf722;color:#7b9cf7;border:1px solid #4a6cf744}
    .badge-gemini{background:#4285f422;color:#7baaf7;border:1px solid #4285f444}
    .badge-groq{background:#f5501622;color:#f55016;border:1px solid #f5501644}

    /* ── Typing ── */
    .typing{display:flex;align-items:center;gap:8px;color:#b8bec8;font-size:14px}
    .typing-spinner{width:14px;height:14px;border:2px solid #4b5563;border-top-color:#d1d5db;border-radius:50%;animation:spin 0.8s linear infinite}
    @keyframes spin{to{transform:rotate(360deg)}}

    /* ── Composer ── */
    .composer{padding:12px;background:var(--top);border-top:1px solid var(--line)}
    .composer-wrap{max-width:900px;margin:0 auto;display:flex;gap:10px}
    textarea{flex:1;width:100%;resize:none;min-height:52px;max-height:200px;height:52px;border-radius:12px;background:#222;color:var(--text);border:1px solid var(--line);padding:12px 14px;font-family:inherit;font-size:17px;line-height:1.5}

    /* ── Home mode ── */
    .main.home-mode .top{border-bottom:none}
    .main.home-mode .messages{display:none}
    .main.home-mode .composer{margin:auto 0 28vh;border-top:none;background:transparent}
    /* home-hero styles moved to BrAInShift section */
    .composer-wrap{transition:max-width .2s ease}
    .main.home-mode .composer-wrap{max-width:980px;width:min(94vw,980px);display:block}
    .main.home-mode textarea{width:100%;min-height:64px;max-height:200px;height:64px;border-radius:28px;padding:18px 108px 18px 20px;overflow-y:auto}
    .textarea-wrap{position:relative;width:100%}
    .composer-box{width:100%}
    .textarea-wrap .send-circle{position:absolute;right:10px;top:50%;transform:translateY(-50%)}
    .main.home-mode .textarea-wrap .send-circle{right:12px}

    /* ── Panneaux flottants ── */
    .params{display:none;position:absolute;right:14px;top:58px;background:#1a1a1e;border:1px solid var(--line);padding:0;border-radius:14px;width:340px;z-index:20;max-height:80vh;overflow-y:auto;box-shadow:0 8px 32px rgba(0,0,0,.5)}
    .params.open{display:block}
    .params-header{display:flex;justify-content:space-between;align-items:center;padding:16px 18px 12px;border-bottom:1px solid var(--line)}
    .params-header h3{margin:0;font-size:15px;font-weight:600;color:#e0e0e0}
    .params-close{background:none;border:none;color:var(--muted);font-size:18px;cursor:pointer;padding:0 4px;line-height:1}
    .params-close:hover{color:#fff}
    .params-section{padding:14px 18px 10px;border-bottom:1px solid #2a2a2e}
    .params-section:last-child{border-bottom:none}
    .params-section-title{font-size:11px;font-weight:700;letter-spacing:.08em;text-transform:uppercase;color:#4abfbf;margin-bottom:10px;display:flex;align-items:center;gap:6px}
    .params-section-title::before{content:'◆';font-size:7px}
    /* Slider row */
    .p-row{margin-bottom:14px}
    .p-row-head{display:flex;justify-content:space-between;align-items:center;margin-bottom:4px}
    .p-row-head label{font-size:13px;font-weight:500;color:#c9d0db}
    .p-row-head .p-val{font-size:13px;font-weight:600;color:#4abfbf;min-width:48px;text-align:right}
    .p-row input[type=range]{-webkit-appearance:none;width:100%;height:5px;border-radius:4px;background:#2a2a2e;outline:none;cursor:pointer}
    .p-row input[type=range]::-webkit-slider-thumb{-webkit-appearance:none;width:18px;height:18px;border-radius:50%;background:#4abfbf;cursor:pointer;border:2px solid #1a1a1e;box-shadow:0 1px 4px rgba(0,0,0,.4)}
    .p-row input[type=range]::-moz-range-thumb{width:18px;height:18px;border-radius:50%;background:#4abfbf;cursor:pointer;border:2px solid #1a1a1e}
    .p-row .p-hint{font-size:11px;color:var(--muted);margin-top:3px;line-height:1.4}
    /* Toggle row */
    .p-toggle{display:flex;justify-content:space-between;align-items:center;margin-bottom:12px}
    .p-toggle label{font-size:13px;font-weight:500;color:#c9d0db;display:flex;align-items:center;gap:6px}
    .p-toggle label .p-toggle-icon{font-size:15px}
    .toggle-switch{position:relative;width:42px;height:24px;flex-shrink:0;cursor:pointer}
    .toggle-switch input{opacity:0;width:0;height:0}
    .toggle-slider{position:absolute;inset:0;background:#3a3a3e;border-radius:24px;transition:background .2s}
    .toggle-slider::before{content:'';position:absolute;width:18px;height:18px;left:3px;top:3px;background:#888;border-radius:50%;transition:transform .2s, background .2s}
    .toggle-switch input:checked+.toggle-slider{background:#4abfbf40}
    .toggle-switch input:checked+.toggle-slider::before{transform:translateX(18px);background:#4abfbf}
    .p-toggle .p-hint{font-size:11px;color:var(--muted);margin-top:2px;line-height:1.3}

    /* ── Bouton Envoyer ── */
    #sendBtn.send-circle{width:38px;height:38px;border-radius:999px;background:#fff;color:#111;border:none;display:inline-flex;align-items:center;justify-content:center;padding:0}
    #sendBtn.send-circle svg{width:18px;height:18px;stroke:#111;stroke-width:3.2;fill:none;stroke-linecap:round;stroke-linejoin:round}
    #sendBtn.send-circle:hover{background:#e8e8e8}

    /* ── Erreur API ── */
    .api-error{background:#7f1d1d;color:#fca5a5;padding:10px 16px;font-size:13px;border-radius:8px;margin:8px auto;max-width:900px;display:none}
    .api-error.visible{display:block}

    /* ── Color picker popup projet ── */
    .color-picker-popup{
      position:fixed;z-index:999;background:#1e1e1e;border:1px solid #3f3f46;
      border-radius:10px;padding:10px;box-shadow:0 8px 32px rgba(0,0,0,.7);
      display:none;flex-wrap:wrap;gap:6px;width:200px;
    }
    .color-picker-popup.open{display:flex}
    .color-swatch{
      width:26px;height:26px;border-radius:50%;cursor:pointer;border:2px solid transparent;
      transition:transform .12s,border-color .12s;flex-shrink:0;
    }
    .color-swatch:hover{transform:scale(1.18);border-color:rgba(255,255,255,.5)}
    .color-swatch.selected{border-color:#fff;transform:scale(1.12)}

    /* ── Modèle actif affiché dans la top bar ── */
    .active-model-chip{
      display:flex;align-items:center;gap:5px;
      background:#ffffff0d;border:1px solid #3f3f4699;
      border-radius:20px;padding:3px 10px;font-size:11px;
      color:var(--muted);white-space:nowrap;max-width:180px;
      overflow:hidden;
    }
    .active-model-chip span.label-txt{overflow:hidden;text-overflow:ellipsis;max-width:140px;display:inline-block;vertical-align:middle}
    .active-model-chip .dot{width:6px;height:6px;border-radius:50%;flex-shrink:0}

    /* ── GitHub panel ── */
    .gh-status{font-size:12px;color:var(--muted);margin-top:8px;min-height:18px}
    .gh-status.ok{color:#22c55e}
    .gh-status.err{color:#f87171}
    .gh-status.warn{color:#fbbf24}
    .gh-btn-row{display:flex;gap:8px;margin-top:10px;flex-wrap:wrap}
    .gh-btn{border:1px solid var(--line);background:#ffffff0d;color:var(--text);
      padding:7px 12px;border-radius:8px;cursor:pointer;font-size:13px;transition:background .15s}
    .gh-btn:hover{background:#ffffff1a}
    .gh-btn.primary{background:#1f6feb;border-color:#1f6feb;color:#fff}
    .gh-btn.primary:hover{background:#2d7ef7}
    .gh-btn:disabled{opacity:.45;cursor:default}
    .gh-auto-row{display:flex;align-items:center;gap:8px;margin-top:10px;font-size:13px;color:var(--muted)}
    .gh-auto-row input[type=checkbox]{accent-color:#1f6feb;width:15px;height:15px;cursor:pointer}

    /* ── Hero BrAInShift ── */
    .home-hero{display:none;flex-direction:column;align-items:center;justify-content:center;
      gap:14px;margin-top:16vh}
    .main.home-mode .home-hero{display:flex}
    .brain-icon{animation:brainFloat 4s ease-in-out infinite}
    @keyframes brainFloat{
      0%,100%{transform:translateY(0)}
      50%{transform:translateY(-8px)}
    }
    .hero-brand{
      font-size:52px;font-weight:700;letter-spacing:-.02em;line-height:1;
      background:linear-gradient(135deg,#4a9fd4 0%,#7b68d4 45%,#d46abf 100%);
      -webkit-background-clip:text;-webkit-text-fill-color:transparent;
      background-clip:text;
    }
    .hero-ai{
      font-style:italic;
      background:linear-gradient(90deg,#4abfbf,#a8d4ff);
      -webkit-background-clip:text;-webkit-text-fill-color:transparent;
      background-clip:text;
    }
    .hero-sub{font-size:15px;color:var(--muted);letter-spacing:.06em;text-transform:uppercase;font-weight:400}

    /* ── Modal création de projet ── */
    .modal-overlay{
      position:fixed;inset:0;background:rgba(0,0,0,.65);z-index:1000;
      display:none;align-items:center;justify-content:center;
    }
    .modal-overlay.open{display:flex}
    .modal-box{
      background:#1e1e1e;border:1px solid var(--line);border-radius:14px;
      padding:22px 24px;width:320px;box-shadow:0 16px 48px rgba(0,0,0,.7);
      display:flex;flex-direction:column;gap:14px;
    }
    .modal-title{font-size:15px;font-weight:600;color:#e2e8f0}
    .modal-label{font-size:12px;color:var(--muted);margin-bottom:4px}
    .modal-input{
      width:100%;background:#161616;border:1px solid var(--line);
      color:var(--text);border-radius:8px;padding:8px 10px;font-size:14px;font-family:inherit;
    }
    .modal-input:focus{outline:none;border-color:#4a9fd4}
    .modal-swatches{display:flex;flex-wrap:wrap;gap:8px;padding:4px 0}
    .modal-swatch{
      width:28px;height:28px;border-radius:50%;cursor:pointer;
      border:2px solid transparent;transition:transform .12s,border-color .12s;
    }
    .modal-swatch:hover{transform:scale(1.15)}
    .modal-swatch.selected{border-color:#fff;transform:scale(1.1)}
    .modal-actions{display:flex;gap:8px;justify-content:flex-end;margin-top:4px}
    .modal-btn{
      padding:7px 16px;border-radius:8px;font-size:13px;cursor:pointer;border:1px solid var(--line);
    }
    .modal-btn.cancel{background:transparent;color:var(--muted)}
    .modal-btn.confirm{background:#1f6feb;border-color:#1f6feb;color:#fff}
    .modal-btn.confirm:hover{background:#2d7ef7}

    /* ── Bandeau coloré sur les projets (bordure gauche) ── */
    .item.project-item{
      border-left:3px solid transparent;
      padding-left:6px;
      border-radius:0 8px 8px 0;
      transition:border-color .2s;
    }

    /* ═══════════════════════════════════════════════
       PANNEAU PROFILS (droite)
    ═══════════════════════════════════════════════ */
    .right-panel{
      width:380px;max-height:80vh;
      flex-direction:column;
      padding:0;
    }
    .right-panel.open{display:flex}
    .right-panel .right-panel-head{
      display:flex;align-items:center;justify-content:space-between;
      padding:14px 16px 10px;border-bottom:1px solid var(--line);
      flex-shrink:0;
    }
    .right-panel-title{font-size:13px;font-weight:600;color:#e2e8f0;letter-spacing:.03em}

    /* Liste des profils */
    .profile-list{flex:1;overflow-y:auto;padding:8px}
    .profile-item{
      display:flex;align-items:center;gap:8px;
      padding:8px 10px;border-radius:9px;cursor:pointer;
      border:1px solid transparent;transition:background .12s,border-color .12s;
      margin-bottom:4px;
    }
    .profile-item:hover{background:#242424}
    .profile-item.active{background:#1e2a3a;border-color:#1f6feb55}
    .profile-icon{font-size:18px;flex-shrink:0;width:28px;text-align:center}
    .profile-name{flex:1;font-size:13px;font-weight:500;overflow:hidden;text-overflow:ellipsis;white-space:nowrap}
    .profile-active-dot{
      width:7px;height:7px;border-radius:50%;background:#1f6feb;
      flex-shrink:0;display:none;
    }
    .profile-item.active .profile-active-dot{display:block}
    .profile-btns{display:flex;gap:3px;opacity:0;transition:opacity .12s}
    .profile-item:hover .profile-btns{opacity:1}
    .profile-btn{
      border:0;background:none;color:var(--muted2);cursor:pointer;
      font-size:12px;padding:2px 4px;border-radius:4px;
    }
    .profile-btn:hover{background:#333;color:#e2e8f0}

    /* Éditeur de profil */
    .profile-editor{
      border-top:1px solid var(--line);padding:12px;
      display:flex;flex-direction:column;gap:10px;
      max-height:60vh;overflow-y:auto;
    }
    .profile-editor.hidden{display:none}
    .pe-title{font-size:12px;font-weight:600;color:#a0aec0;letter-spacing:.04em;text-transform:uppercase}
    .pe-row{display:flex;gap:8px;align-items:center}
    .pe-input{
      flex:1;background:#161616;border:1px solid var(--line);color:var(--text);
      border-radius:8px;padding:7px 10px;font-size:13px;font-family:inherit;
    }
    .pe-input:focus{outline:none;border-color:#4a9fd4}
    .pe-emoji{
      width:42px;height:34px;background:#161616;border:1px solid var(--line);
      color:var(--text);border-radius:8px;text-align:center;font-size:18px;cursor:pointer;
    }
    /* ── Pièces jointes ── */
    .attach-btn{
      position:absolute;right:54px;top:50%;transform:translateY(-50%);
      background:none;border:none;color:var(--muted2);
      font-size:22px;cursor:pointer;padding:2px 5px;border-radius:6px;
      transition:color .15s, background .15s;line-height:1;font-weight:300;
    }
    .attach-btn:hover{color:#7baaf7;background:#7baaf720}
    .file-preview-area{
      display:flex;flex-wrap:wrap;gap:6px;
      padding:8px 52px 0 12px; /* padding-right pour éviter chevauchement avec les boutons */
    }
    .file-preview-area:empty{display:none}
    .file-chip{
      display:flex;align-items:center;gap:5px;
      background:#2a2a2a;border:1px solid #3f3f46;border-radius:8px;
      padding:3px 8px 3px 5px;font-size:12px;color:#c9d0db;max-width:200px;
    }
    .file-chip img{width:32px;height:32px;object-fit:cover;border-radius:4px;flex-shrink:0}
    .file-chip .file-icon{font-size:22px;flex-shrink:0;line-height:1}
    .file-chip .file-name{overflow:hidden;text-overflow:ellipsis;white-space:nowrap;flex:1}
    .file-chip .file-remove{
      background:none;border:none;color:var(--muted2);cursor:pointer;
      font-size:14px;padding:0 0 0 3px;line-height:1;flex-shrink:0;
    }
    .file-chip .file-remove:hover{color:#f87171}
    /* Textarea : padding-right pour laisser place à ＋ + bouton envoi */
    .textarea-wrap textarea{padding-right:100px}

    .pe-textarea{
      width:100%;background:#0f0f0f;border:1px solid var(--line);color:#d4d8e0;
      border-radius:8px;padding:10px 12px;font-size:12.5px;font-family:"SFMono-Regular",monospace;
      line-height:1.6;resize:vertical;min-height:160px;max-height:380px;
    }
    .pe-textarea:focus{outline:none;border-color:#4a9fd4}
    .pe-actions{display:flex;gap:8px;flex-wrap:wrap}
    .pe-btn{
      padding:6px 14px;border-radius:8px;font-size:12px;cursor:pointer;
      border:1px solid var(--line);background:#ffffff0d;color:var(--text);transition:background .12s;
    }
    .pe-btn:hover{background:#ffffff1a}
    .pe-btn.primary{background:#1f6feb;border-color:#1f6feb;color:#fff}
    .pe-btn.primary:hover{background:#2d7ef7}
    .pe-btn.danger{border-color:#ef444455;color:#f87171}
    .pe-btn.danger:hover{background:#ef444422}

    /* Chip profil actif dans la topbar */
    .active-profile-chip{
      display:inline-flex;align-items:center;gap:5px;
      background:#1f6feb18;border:1px solid #1f6feb44;
      border-radius:20px;padding:3px 10px 3px 7px;font-size:11px;
      color:#7baaf7;white-space:nowrap;cursor:pointer;
    }
    .active-profile-chip:hover{background:#1f6feb28}
    .active-profile-chip span{font-size:14px}

    /* ── Panneau clés API redessiné ── */
    #apiKeyPanel{
      right:0 !important;
      top:46px !important;
      width:380px !important;
      max-height:85vh;
      overflow-y:auto;
    }
    .key-row{display:flex;flex-direction:column;gap:5px;padding:8px 0;border-bottom:1px solid #2c2c2c}
    .key-row:last-child{border-bottom:none}
    .key-header{display:flex;align-items:center;justify-content:space-between}
    .key-label{font-size:11px;font-weight:700;color:#9ca3af;letter-spacing:.06em;text-transform:uppercase}
    .key-status{font-size:11px;display:flex;align-items:center;gap:5px}
    .key-dot{width:7px;height:7px;border-radius:50%;flex-shrink:0}
    .key-input-row{display:flex;gap:6px}
    .key-input{
      flex:1;background:#161616;border:1px solid var(--line);
      color:var(--text);border-radius:7px;padding:7px 10px;
      font-size:12px;font-family:monospace;
      transition:border-color .15s;
    }
    .key-input:focus{outline:none;border-color:#4a9fd4}
    .key-input.has-key{border-color:#22c55e44}
    .key-test-btn{
      padding:0 10px;border:1px solid var(--line);background:#ffffff0d;
      color:var(--muted);border-radius:7px;cursor:pointer;font-size:11px;
      white-space:nowrap;transition:background .12s;
    }
    .key-test-btn:hover{background:#ffffff1a;color:#e2e8f0}
    .key-test-result{font-size:11px;min-height:14px;padding:2px 0}
    .save-keys-btn{
      width:100%;padding:9px;border-radius:8px;background:#1f6feb;
      border:none;color:#fff;font-size:13px;font-weight:600;cursor:pointer;
      margin-top:8px;transition:background .15s;
    }
    .save-keys-btn:hover{background:#2d7ef7}
    .save-keys-btn.saved{background:#22c55e}

    /* ── Markdown headings dans les réponses ── */
    .md-heading{margin:14px 0 8px;line-height:1.35;color:#e8eaee}
    .assistant-body h3.md-heading{font-size:17px;font-weight:700;border-bottom:1px solid #3f3f4660;padding-bottom:4px}
    .assistant-body h4.md-heading{font-size:15px;font-weight:600;color:#b0c4d8}
    .assistant-body hr{border:none;border-top:1px solid #3f3f46;margin:12px 0}

    /* ── KaTeX rendu LaTeX ── */
    .katex-display{
      background:#141a26;
      border-left:3px solid #4a80c4;
      border-radius:8px;
      padding:12px 20px;
      margin:14px 0;
      overflow-x:auto;
    }
    .katex-display > .katex{
      font-size:1.15em;
    }
    /* Inline KaTeX */
    .katex{
      font-size:1em;
      color:#c8deff;
    }
    /* Fond léger pour inline */
    .katex-inline-wrap{
      background:#1a2235;
      border-radius:4px;
      padding:1px 4px;
      display:inline;
    }
    /* Erreur KaTeX → fallback texte */
    .katex-error-fallback{
      font-family:monospace;
      font-size:.9em;
      color:#a8d4ff;
      background:#1a2030;
      border-left:3px solid #4a80c4;
      border-radius:4px;
      padding:6px 12px;
      display:block;
      margin:10px 0;
    }

    /* ════ Rendu Markdown professionnel (inspiré IA-Genius) ════ */
    .assistant-body{font-size:18px;line-height:1.65;color:var(--text);word-wrap:break-word;overflow-wrap:break-word}
    .assistant-body p{margin:0 0 12px}
    .assistant-body p:last-child{margin-bottom:0}
    .assistant-body strong{font-weight:700;color:#f0eeeb}
    .assistant-body em{font-style:italic;color:#d0cec8}
    .assistant-body h1,.assistant-body h2,.assistant-body h3,.assistant-body h4{
      font-weight:700;letter-spacing:-.02em;color:#f5f3f0;margin:18px 0 8px;line-height:1.3
    }
    .assistant-body h1{font-size:24px;padding-bottom:6px;border-bottom:2px solid #3f3f46}
    .assistant-body h2{font-size:20px;padding-bottom:5px;border-bottom:1px solid #3f3f46}
    .assistant-body h3{font-size:18px}
    .assistant-body h4{font-size:16px;color:var(--muted)}
    .assistant-body h1:first-child,.assistant-body h2:first-child,.assistant-body h3:first-child{margin-top:4px}
    .assistant-body ul,.assistant-body ol{margin:4px 0 12px 24px;padding:0}
    .assistant-body li{margin-bottom:4px;line-height:1.6;font-size:18px}
    .assistant-body li>p{margin-bottom:2px}
    .assistant-body li>ul,.assistant-body li>ol{margin-top:2px;margin-bottom:2px}
    .assistant-body ul li::marker{color:#4a9fd4}
    .assistant-body ol li::marker{color:#4a9fd4;font-weight:600}
    .assistant-body blockquote{
      border-left:3px solid #4b5563;padding:8px 14px;margin:12px 0;
      background:#1e2330;border-radius:0 6px 6px 0;color:#9ca3af;font-style:italic
    }
    .assistant-body blockquote p:last-child{margin-bottom:0}
    .assistant-body code{
      font-family:"JetBrains Mono","SFMono-Regular",Consolas,monospace;font-size:.87em;
      background:rgba(110,118,129,.15);padding:2px 6px;border-radius:5px;color:#e8c9b8
    }
    .assistant-body pre{
      margin:14px 0;border-radius:10px;overflow:hidden;
      border:1px solid var(--line);box-shadow:0 2px 8px rgba(0,0,0,.2)
    }
    .assistant-body pre code{
      display:block;padding:14px 16px;background:#0d1117;
      overflow-x:auto;line-height:1.6;font-size:13px;color:#e6edf3;border-radius:0
    }
    .assistant-body .code-block-header{
      display:flex;justify-content:space-between;align-items:center;
      padding:7px 12px;background:#161b22;font-size:11px;color:#6b7280;
      font-family:"JetBrains Mono",monospace;border-bottom:1px solid #21262d
    }
    .assistant-body .copy-code-btn{
      background:none;border:1px solid #30363d;color:#6b7280;
      padding:2px 8px;border-radius:5px;font-size:11px;cursor:pointer;font-family:inherit
    }
    .assistant-body .copy-code-btn:hover{color:#e6edf3;border-color:#484f58}
    /* ── Bloc de code replié (>50 lignes) ── */
    .collapsed-code{border:1px solid #30363d;border-radius:8px;overflow:hidden;margin:10px 0}
    .collapsed-code .code-header{display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:6px}
    .collapsed-code details pre{max-height:600px;overflow:auto;margin:0}
    .collapsed-code details summary{display:none}
    .assistant-body table{
      width:100%;border-collapse:separate;border-spacing:0;
      margin:14px 0;font-size:15px;border-radius:8px;border:1px solid var(--line);overflow:hidden
    }
    .assistant-body thead{background:var(--panel)}
    .assistant-body th{
      padding:9px 13px;font-weight:700;text-align:left;
      color:var(--text);font-size:13px;text-transform:uppercase;
      letter-spacing:.04em;border-bottom:2px solid var(--line)
    }
    .assistant-body td{padding:8px 13px;border-bottom:1px solid var(--line);color:var(--text)}
    .assistant-body tbody tr:last-child td{border-bottom:none}
    .assistant-body tbody tr:nth-child(even){background:rgba(255,255,255,.02)}
    .assistant-body hr{border:none;height:1px;background:var(--line);margin:18px 0}
    .assistant-body a{color:#7baaf7;text-decoration:none;border-bottom:1px solid transparent;transition:border-color .15s}
    .assistant-body a:hover{border-bottom-color:#7baaf7}
    /* ── KaTeX dans les réponses ── */
    .assistant-body .katex-display{overflow-x:auto;padding:4px 0;text-align:center;margin:0}
    .assistant-body .katex{font-size:1.05em}
    .assistant-body .katex-display>.katex{font-size:1.2em}
    .assistant-body .katex-block-wrap{
      background:#141a26;border-left:3px solid #4a80c4;border-radius:8px;
      padding:10px 18px;margin:10px 0;overflow-x:auto;text-align:center
    }
    .assistant-body .katex-inline-wrap{display:inline}
    /* Formules chimiques inline auto-converties depuis <code> */
    .assistant-body .chem-inline{display:inline-baseline;background:transparent;padding:0;border:0;font-family:inherit}
    .assistant-body .chem-inline .katex{font-size:1.05em}
    .katex-fallback-block{
      font-family:"JetBrains Mono",monospace;font-size:.92em;color:#a8d4ff;
      background:#141a26;border-left:3px solid #4a80c4;border-radius:8px;
      padding:8px 16px;margin:10px 0;display:block;overflow-x:auto
    }
    .katex-fallback-inline{
      font-family:"JetBrains Mono",monospace;font-size:.9em;color:#a8d4ff;
      background:#1a2235;border-radius:4px;padding:1px 5px
    }

    /* ═══════════════════════════════════════════════
       MOTEUR DE RECHERCHE CONVERSATIONS
    ═══════════════════════════════════════════════ */
    .search-box{
      position:relative;
      padding:2px 0 6px;
      margin-bottom:4px;
    }
    .search-input-wrap{
      position:relative;display:flex;align-items:center;
    }
    .search-input-wrap .search-icon{
      position:absolute;left:10px;color:var(--muted2);font-size:14px;
      pointer-events:none;transition:color .15s;
    }
    .search-input{
      width:100%;background:#1a1a1e;border:1px solid #2c2c2e;
      color:var(--text);border-radius:10px;padding:9px 34px 9px 32px;
      font-size:13px;font-family:inherit;transition:border-color .2s,box-shadow .2s;
      outline:none;
    }
    .search-input::placeholder{color:#5a5f6a}
    .search-input:focus{border-color:#4a6cf7;box-shadow:0 0 0 2px #4a6cf720}
    .search-input:focus ~ .search-icon{color:#7b9cf7}
    .search-clear{
      position:absolute;right:8px;background:none;border:none;
      color:#6b7280;font-size:15px;cursor:pointer;padding:2px 4px;
      border-radius:4px;line-height:1;display:none;
    }
    .search-clear:hover{color:#e2e8f0;background:#ffffff15}
    .search-input:not(:placeholder-shown) ~ .search-clear{display:block}

    /* ── Résultats de recherche (dropdown) ── */
    .search-results{
      position:absolute;top:100%;left:0;right:0;
      background:#1a1a1e;border:1px solid #2c2c2e;
      border-radius:12px;margin-top:4px;
      max-height:65vh;overflow-y:auto;
      box-shadow:0 12px 40px rgba(0,0,0,.55);
      z-index:80;display:none;
    }
    .search-results.open{display:block}
    .search-results-header{
      display:flex;justify-content:space-between;align-items:center;
      padding:10px 14px 8px;border-bottom:1px solid #2a2a2e;
      font-size:11px;color:var(--muted);font-weight:600;
      letter-spacing:.04em;text-transform:uppercase;
      position:sticky;top:0;background:#1a1a1e;z-index:1;
      border-radius:12px 12px 0 0;
    }
    .search-results-count{
      font-size:10px;color:#4a6cf7;background:#4a6cf715;
      padding:2px 8px;border-radius:10px;font-weight:600;
    }
    .search-result-item{
      padding:10px 14px;cursor:pointer;
      border-bottom:1px solid #1f1f24;
      transition:background .12s;
    }
    .search-result-item:last-child{border-bottom:none}
    .search-result-item:hover{background:#ffffff08}
    .search-result-item.active{background:#1e2a3a}
    .search-result-title{
      font-size:13px;font-weight:600;color:#e2e8f0;
      display:flex;align-items:center;gap:6px;
      margin-bottom:3px;
    }
    .search-result-title .proj-badge{
      font-size:9px;padding:1px 6px;border-radius:6px;
      font-weight:600;letter-spacing:.03em;
    }
    .search-result-preview{
      font-size:12px;color:#8a8f9c;line-height:1.5;
      display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;
      overflow:hidden;word-break:break-word;
    }
    .search-result-preview mark{
      background:#4a6cf730;color:#a8c0ff;border-radius:2px;
      padding:0 1px;font-weight:500;
    }
    .search-result-meta{
      display:flex;gap:8px;margin-top:4px;font-size:10px;color:#5a5f6a;
    }
    .search-result-meta .model-tag{
      background:#ffffff0a;padding:1px 6px;border-radius:4px;
    }
    .search-empty{
      padding:24px 14px;text-align:center;
      color:#5a5f6a;font-size:13px;
    }
    .search-empty-icon{font-size:28px;margin-bottom:8px;display:block;opacity:.5}

    /* ── Kbd shortcut hint ── */
    .search-kbd{
      font-size:10px;color:#4a4f5a;background:#1e1e22;
      border:1px solid #2c2c2e;border-radius:4px;
      padding:1px 5px;font-family:monospace;margin-left:auto;
    }

    /* ═══════════════════════════════════════════════════════
       RESPONSIVE — iPad / Tablettes (≤ 1024px)
       Ces règles ne s'appliquent QUE sur petit écran.
       Aucun impact sur les écrans > 1024px (Mac, PC).
    ═══════════════════════════════════════════════════════ */

    @media (max-width: 1024px) {
      /* ── Sidebar : overlay au lieu de flex ── */
      .sidebar {
        position: fixed;
        left: 0; top: 0;
        height: 100vh; height: 100dvh;
        z-index: 50;
        width: 280px !important;
        min-width: 0;
        max-width: 85vw;
        box-shadow: 4px 0 24px rgba(0,0,0,.5);
        transform: translateX(0);
        transition: transform .22s cubic-bezier(.4,0,.2,1);
      }
      .app.sidebar-collapsed .sidebar {
        transform: translateX(-100%);
        width: 280px !important;
        padding: 10px;
        border-right: 1px solid var(--line);
      }

      /* Backdrop quand sidebar ouverte */
      .sidebar-backdrop {
        display: none;
        position: fixed; inset: 0;
        background: rgba(0,0,0,.35);
        z-index: 49;
      }
      .app:not(.sidebar-collapsed) .sidebar-backdrop { display: block; }

      /* ── Divider : invisible sur tactile ── */
      .resizer { display: none; }

      /* ── Zone principale : pleine largeur ── */
      .main { min-width: 0; width: 100%; }

      /* ── Barre du haut : compacte ── */
      .top { padding: 8px 10px; gap: 6px; }
      .top .btn { min-width: 44px; min-height: 44px; font-size: 18px; }
      #modelSelect { font-size: 13px; max-width: 160px; }

      /* ── Panneaux dropdown : pleine largeur ── */
      .params {
        right: 6px !important;
        left: 6px !important;
        width: auto !important;
        max-width: none;
        top: 52px !important;
        max-height: 70vh;
      }
      .right-panel {
        right: 6px !important;
        left: 6px !important;
        width: auto !important;
        top: 52px !important;
        max-height: 70vh;
      }

      /* ── Zone de saisie ── */
      .input-area { padding: 8px 10px; }
      .textarea-wrap textarea {
        font-size: 16px !important; /* évite le zoom auto iOS */
        padding-right: 130px;
        min-height: 48px;
      }

      /* ── Boutons tactiles : 44px minimum ── */
      .attach-btn {
        min-width: 44px; min-height: 44px;
        font-size: 24px;
        display: inline-flex; align-items: center; justify-content: center;
      }
      #sendBtn.send-circle {
        width: 44px; height: 44px;
      }
      #sendBtn.send-circle svg { width: 20px; height: 20px; }

      /* ── Messages : marges réduites ── */
      .msg-row { padding: 10px 12px; }
      .msg-body { max-width: 95%; }

      /* ── Recherche sidebar ── */
      .search-input { font-size: 16px !important; padding: 11px 34px 11px 32px; }

      /* ── Home mode : texte plus petit ── */
      .main.home-mode h1 { font-size: 1.6em; }

      /* ── Code blocks : scroll horizontal ── */
      pre { max-width: 100%; overflow-x: auto; }
      .code-header { flex-wrap: wrap; gap: 4px; }

      /* ── Tableaux : scroll horizontal ── */
      .assistant-body table { display: block; overflow-x: auto; }
      .assistant-body table td, .assistant-body table th { white-space: normal; }

      /* ── KaTeX : empêcher débordement ── */
      .katex-block { overflow-x: auto; -webkit-overflow-scrolling: touch; }
      .katex-display { overflow-x: auto; -webkit-overflow-scrolling: touch; padding: 10px 12px; }
    }

    /* ── iPhone (≤ 480px) ── */
    @media (max-width: 480px) {

      /* ── Safe areas (encoche + barre home) ── */
      .app { padding: env(safe-area-inset-top) 0 0 0; }
      .input-area { padding-bottom: calc(8px + env(safe-area-inset-bottom)); }

      /* ── Sidebar overlay plus étroite ── */
      .sidebar { width: 82vw !important; max-width: 320px; }

      /* ── Topbar : compacte sur une ligne ── */
      .top {
        padding: 6px 8px;
        gap: 4px;
      }
      .top .btn {
        padding: 6px 7px;
        font-size: 16px;
        min-width: 40px; min-height: 40px;
      }
      #modelSelect {
        max-width: 100px;
        font-size: 11px;
        padding: 6px 4px;
      }

      /* ── Chip profil : icône seule, masquer le texte ── */
      .active-profile-chip #chipProfileName { display: none; }
      .active-profile-chip {
        padding: 4px 8px;
        gap: 0;
        min-width: 36px;
        justify-content: center;
      }

      /* ── Panneaux dropdown : plein écran ── */
      .params, .right-panel {
        position: fixed !important;
        top: 0 !important; left: 0 !important; right: 0 !important;
        bottom: 0 !important;
        width: 100vw !important;
        max-height: 100vh !important;
        max-height: 100dvh !important;
        border-radius: 0 !important;
        z-index: 60 !important;
      }

      /* ══════════════════════════════════════════════════
         ANTI-DÉBORDEMENT — Rien ne doit dépasser l'écran
      ══════════════════════════════════════════════════ */

      /* Container messages : couper tout débordement */
      #messages { overflow-x: hidden !important; }

      /* Msg row : largeur stricte viewport */
      .msg-row {
        width: 100% !important;
        max-width: 100vw !important;
        padding: 8px 8px;
        box-sizing: border-box;
      }

      /* Assistant : écraser le max-width:78ch qui fait ~1100px */
      .msg.assistant {
        max-width: 100% !important;
        width: 100% !important;
        font-size: 15px;
        overflow-wrap: break-word !important;
        word-break: break-word !important;
      }
      .msg-row.assistant > div {
        max-width: 100% !important;
        min-width: 0;
      }

      /* User : idem */
      .msg-row.user > div { max-width: 88% !important; }

      /* Assistant body : tout doit wrapper */
      .assistant-body {
        font-size: 14px;
        line-height: 1.55;
        overflow-wrap: break-word !important;
        word-break: break-word !important;
        overflow-x: hidden !important;
        max-width: 100% !important;
      }
      .assistant-body * {
        max-width: 100% !important;
        box-sizing: border-box;
      }

      /* Tableaux : scroll horizontal, texte wrappé dans les cellules */
      .assistant-body table {
        display: block !important;
        overflow-x: auto !important;
        -webkit-overflow-scrolling: touch;
        max-width: 100% !important;
        font-size: 12px;
      }
      .assistant-body td, .assistant-body th {
        white-space: normal !important;
        word-break: break-word !important;
        min-width: 60px;
        padding: 6px 8px !important;
      }

      /* Code : scroll horizontal, jamais déborder le parent */
      .assistant-body pre {
        max-width: calc(100vw - 32px) !important;
        overflow-x: auto !important;
        -webkit-overflow-scrolling: touch;
        font-size: 12px !important;
        margin: 8px 0 !important;
      }
      .assistant-body pre code {
        white-space: pre !important;
        word-break: normal !important;
      }
      .assistant-body code {
        word-break: break-all !important;
        font-size: 13px;
      }

      /* KaTeX : scroll horizontal, pas de débordement */
      .katex-block, .katex-display, .katex-block-wrap {
        overflow-x: auto !important;
        -webkit-overflow-scrolling: touch;
        max-width: calc(100vw - 32px) !important;
        padding: 6px 8px !important;
      }
      .katex { font-size: 0.9em !important; }

      /* Images dans les réponses */
      .assistant-body img {
        max-width: 100% !important;
        height: auto !important;
      }

      /* Blockquotes */
      .assistant-body blockquote {
        margin-left: 8px !important;
        margin-right: 0 !important;
        padding-left: 10px !important;
      }

      /* ── Menu export : plus grand pour le tactile ── */
      .export-menu { min-width: 220px; }
      .export-menu .ex-item { padding: 12px 14px; font-size: 14px; }

      /* ── Zone de saisie ── */
      .input-area { padding: 6px 6px; }
      .textarea-wrap textarea {
        font-size: 16px !important;
        min-height: 44px;
        padding: 10px 90px 10px 12px;
        border-radius: 22px;
      }
      .attach-btn {
        right: 50px;
        font-size: 22px;
        min-width: 40px; min-height: 40px;
      }
      #sendBtn.send-circle { width: 40px; height: 40px; }

      /* ── Recherche sidebar ── */
      .search-input { font-size: 16px !important; }
      .search-results { max-height: 55vh; }
      .search-result-item { padding: 12px 14px; }

      /* ── Code : header compact ── */
      .code-header { font-size: 11px; padding: 4px 8px; }
      .copy-code-btn { font-size: 11px; padding: 3px 6px; }

      /* ── Home mode ── */
      .main.home-mode h1 { font-size: 1.3em; }
      .main.home-mode .home-subtitle { font-size: 13px; }

      /* ── Profil éditeur : champs plus grands ── */
      .pe-input, .pe-emoji { font-size: 16px !important; min-height: 44px; }
      .pe-textarea { font-size: 16px !important; min-height: 120px; }
      .pe-btn { min-height: 44px; font-size: 14px; }

      /* ── GitHub panel inputs ── */
      #githubPanel input { font-size: 16px !important; min-height: 40px; }
      #githubPanel .btn, #githubPanel button { min-height: 44px; }

      /* ── API Key panel inputs ── */
      #apiKeyPanel input { font-size: 16px !important; min-height: 40px; }

      /* ── Chat items sidebar : plus grands pour le tactile ── */
      .item { padding: 10px 10px; min-height: 44px; }
      .chat-menu-btn { opacity: 1; font-size: 18px; padding: 6px 8px; }
    }

    /* ── Hauteur viewport dynamique (clavier virtuel iOS) ── */
    @supports (height: 100dvh) {
      @media (max-width: 1024px) {
        .app { height: 100dvh; }
        .sidebar { height: 100dvh; }
      }
    }

