<body>
<!-- VERSION_FIXED_V8 -->
<div class="app">
  <!-- Backdrop pour fermer la sidebar sur tablette (invisible sur desktop) -->
  <div class="sidebar-backdrop" id="sidebarBackdrop"></div>
  <aside class="sidebar">
    <!-- Moteur de recherche conversations -->
    <div class="search-box" id="searchBox">
      <div class="search-input-wrap">
        <span class="search-icon">🔍</span>
        <input class="search-input" id="searchInput" type="text"
               placeholder="Rechercher…" autocomplete="off" spellcheck="false" />
        <button class="search-clear" id="searchClear" title="Effacer">✕</button>
      </div>
      <div class="search-results" id="searchResults"></div>
    </div>
    <div id="chatList"></div>
  </aside>
  <div class="resizer" id="resizer"></div>

  <section class="main">
    <div class="top">
      <div style="display:flex;gap:8px;align-items:center">
        <button class="btn" id="toggleSidebarBtn" title="Ouvrir/Fermer la barre latérale">☰</button>
        <select id="modelSelect"></select>
      </div>
      <div style="display:flex;gap:8px;align-items:center;position:relative">
        <!-- Chip profil actif -->
        <div class="active-profile-chip" id="activeProfileChip" onclick="el('toggleRightPanelBtn').click()" title="Profil système actif">
          <span id="chipProfileIcon">🤖</span>
          <span id="chipProfileName">Aucun profil</span>
        </div>
