      prompt: "Tu es un assistant IA expert et polyvalent. Réponds de manière précise, structurée et professionnelle. N'utilise jamais de balises HTML dans tes réponses. Utilise Markdown pour la mise en forme."
    }
  ],
  activeProfiles: JSON.parse(localStorage.getItem("activeProfiles") || "[]"),
