/** Détecte le type de fichier par extension si le MIME est inconnu */
function guessMetaFromName(name) {
  const ext = (name || '').split('.').pop().toLowerCase();
  const map = {
    html:'🌐 HTML', htm:'🌐 HTML', css:'🎨 CSS', js:'📜 JS', jsx:'📜 JSX', tsx:'📜 TSX',
    ts:'📜 TS', json:'📋 JSON', md:'📝 MD', txt:'📄 TXT', csv:'📊 CSV',
    py:'🐍 Python', xml:'📋 XML', yaml:'📋 YAML', yml:'📋 YAML', sql:'🗃 SQL',
    sh:'⚙ Shell', bat:'⚙ Batch', log:'📄 Log', ini:'📋 INI', cfg:'📋 Config',
    env:'📋 ENV', toml:'📋 TOML', rb:'💎 Ruby', java:'☕ Java',
    c:'📜 C', cpp:'📜 C++', h:'📜 Header', rs:'🦀 Rust', go:'📜 Go', php:'📜 PHP',
    swift:'📜 Swift', kt:'📜 Kotlin'
  };
  const label = map[ext];
  if (label) {
    const [icon, ...rest] = label.split(' ');
    return { icon, label: rest.join(' '), supported: true, isText: true };
  }
  return { icon: '📎', label: ext || 'Fichier', supported: false };
}

/** Extrait le texte d'un fichier Office côté navigateur */
async function extractOfficeText(file) {
  const ext = file.name.split('.').pop().toLowerCase();
  const ab  = await file.arrayBuffer();

  // .docx → mammoth
  if ((ext === 'docx' || ext === 'doc') && typeof mammoth !== 'undefined') {
    const res = await mammoth.extractRawText({ arrayBuffer: ab });
    return res.value?.trim() || null;
  }

  // .xlsx / .xls → SheetJS
  if ((ext === 'xlsx' || ext === 'xls') && typeof XLSX !== 'undefined') {
    const wb  = XLSX.read(ab, { type: 'array' });
    const lines = [];
    wb.SheetNames.forEach(name => {
      lines.push(`=== Feuille : ${name} ===`);
      lines.push(XLSX.utils.sheet_to_csv(wb.Sheets[name]));
    });
    return lines.join('\n').trim() || null;
  }

  // .pptx → JSZip (extraction propre des slides XML)
  if (ext === 'pptx' && typeof JSZip !== 'undefined') {
    try {
      const zip = await JSZip.loadAsync(ab);
      const slideTexts = [];
      // Les slides sont dans ppt/slides/slide1.xml, slide2.xml, etc.
      const slideFiles = Object.keys(zip.files)
        .filter(f => /^ppt\/slides\/slide\d+\.xml$/i.test(f))
        .sort((a, b) => {
          const na = parseInt(a.match(/slide(\d+)/)[1]);
          const nb = parseInt(b.match(/slide(\d+)/)[1]);
          return na - nb;
        });
      for (const slideFile of slideFiles) {
        const xml = await zip.files[slideFile].async('text');
        const texts = [];
        const re = /<a:t[^>]*>([^<]+)<\/a:t>/g;
        let m;
        while ((m = re.exec(xml)) !== null) texts.push(m[1]);
        if (texts.length) {
          const slideNum = slideFile.match(/slide(\d+)/)[1];
          slideTexts.push(`--- Diapositive ${slideNum} ---\n${texts.join(' ')}`);
        }
      }
      return slideTexts.join('\n\n').trim() || null;
    } catch(e) {
      console.warn('[BrAInShift] ⚠ Extraction PPTX échouée:', e.message);
      return null;
    }
  }

  // .pptx fallback sans JSZip (regex brute, moins fiable)
  if (ext === 'pptx') {
    try {
      const bytes = new Uint8Array(ab);
      const str   = new TextDecoder('utf-8', { fatal: false }).decode(bytes);
      const texts = [];
      const re = /<a:t[^>]*>([^<]+)<\/a:t>/g;
      let m;
      while ((m = re.exec(str)) !== null) texts.push(m[1]);
      return texts.join(' ').trim() || null;
    } catch(e) { return null; }
  }

  return null; // non extractible
}

/** Extrait le texte d'un PDF côté navigateur via pdf.js */
async function extractPdfText(data) {
  if (typeof pdfjsLib === 'undefined') return null;
  try {
    const binary = atob(data);
    const bytes  = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);

    const pdf = await pdfjsLib.getDocument({ data: bytes }).promise;
    const pages = [];
    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const content = await page.getTextContent();
      const text = content.items.map(item => item.str).join(' ');
      if (text.trim()) pages.push(`--- Page ${i}/${pdf.numPages} ---\n${text.trim()}`);
    }
    return pages.join('\n\n').trim() || null;
  } catch (e) {
    console.warn('[BrAInShift] ⚠ Extraction PDF échouée:', e.message);
    return null;
  }
}

el('fileInput').onchange = async e => {
  const files = [...e.target.files];
  for (const file of files) {
    const meta = SUPPORTED_TYPES[file.type] || guessMetaFromName(file.name);
    const ext  = (file.name || '').split('.').pop().toLowerCase();
    const isImage = file.type.startsWith('image/') || /^(jpg|jpeg|png|gif|webp|bmp|svg)$/.test(ext);
    const isPdf   = file.type === 'application/pdf' || ext === 'pdf';

    // Lire en base64 (pour images et PDF)
    const data = await new Promise((res, rej) => {
      const r = new FileReader();
      r.onload = () => res(r.result.split(',')[1]);
      r.onerror = rej;
      r.readAsDataURL(file);
    });

    // Tentative d'extraction texte pour Office ou lecture directe pour fichiers texte
    let extractedText = null;
    if (isPdf) {
      // Extraire le texte du PDF (fallback pour providers qui ne supportent pas les PDFs natifs)
      try { extractedText = await extractPdfText(data); } catch(e) {}
    } else if (!isImage) {
      // Fichiers texte/code : lecture directe
      const isTextFile = meta.isText || /\.(html?|css|js|jsx|tsx|ts|json|md|txt|csv|py|xml|yaml|yml|sql|sh|bat|log|ini|cfg|env|toml|rb|java|c|cpp|h|hpp|rs|go|php|swift|kt)$/i.test(file.name);
      if (isTextFile) {
        try {
          extractedText = await new Promise((res, rej) => {
            const r = new FileReader();
            r.onload = () => res(r.result);
            r.onerror = rej;
            r.readAsText(file);
          });
        } catch(e) {}
      } else {
        try { extractedText = await extractOfficeText(file); } catch(e) {}
      }
    }

    pendingFiles.push({
      name: file.name, type: file.type, data,
      isImage, isPdf,
      extractedText,   // texte extrait (null si non dispo)
      supported: isImage || isPdf || extractedText !== null,
      icon: meta.icon, label: meta.label,
      objectUrl: isImage ? URL.createObjectURL(file) : null
    });
  }
  e.target.value = '';
  renderFilePreview();
};

function renderFilePreview() {
  const area = el('filePreviewArea');
  area.innerHTML = '';
  pendingFiles.forEach((f, i) => {
    const chip = document.createElement('div');
    chip.className = 'file-chip';
    chip.style.border = f.supported ? '1px solid #3f3f46' : '1px solid #f8717144';
    if (f.objectUrl) {
      chip.innerHTML = `<img src="${f.objectUrl}" alt="${f.name}">`;
    } else {
      chip.innerHTML = `<span class="file-icon" title="${f.label}">${f.icon}</span>`;
    }
    chip.innerHTML += `<span class="file-name" title="${f.name}">${f.name}</span>`;
    if (f.extractedText) {
      chip.innerHTML += `<span style="font-size:10px;color:#4ade80;margin-left:3px" title="Texte extrait (${f.extractedText.length} caractères)">✓</span>`;
    } else if (!f.supported) {
      chip.innerHTML += `<span style="font-size:10px;color:#f87171;margin-left:3px" title="Ce format n'est pas extractible directement">⚠</span>`;
    }
    chip.innerHTML += `<button class="file-remove" data-i="${i}" title="Supprimer">✕</button>`;
    chip.querySelector('.file-remove').onclick = ev => {
      ev.stopPropagation();
      if (pendingFiles[i].objectUrl) URL.revokeObjectURL(pendingFiles[i].objectUrl);
      pendingFiles.splice(i, 1);
      renderFilePreview();
    };
    area.appendChild(chip);
  });
}

/** Construit le contenu multimodal d'un message user avec fichiers */
function buildUserContent(text, files) {
  if (!files || !files.length) return text;
  const parts = [];
  for (const f of files) {
    if (f.isImage) {
      // Fallback MIME si le navigateur n'a pas détecté le type
      const imgMime = f.type && f.type.startsWith('image/') ? f.type : 'image/png';
      parts.push({ type: 'image', source: { type: 'base64', media_type: imgMime, data: f.data } });
    } else if (f.isPdf) {
      parts.push({ type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: f.data },
        title: f.name, _extractedText: f.extractedText || null });
    } else if (f.extractedText) {
      // Fichier Office : texte extrait côté navigateur
      // Limiter à ~100 000 caractères pour éviter les timeouts API
      let txt = f.extractedText;
      let truncNote = '';
      if (txt.length > 100000) {
        txt = txt.slice(0, 100000);
        truncNote = `\n\n[⚠ Document tronqué : ${f.extractedText.length} → 100 000 caractères pour respecter les limites du modèle]`;
      }
      parts.push({ type: 'text', text: `[${f.icon} Contenu du fichier "${f.name}" :]\n\n${txt}${truncNote}` });
    } else {
      // Fichier non extractible
      parts.push({ type: 'text', text: `[Fichier joint : ${f.icon} ${f.name} — contenu non extractible. Veuillez copier-coller le texte.]` });
    }
  }
  if (text) parts.push({ type: 'text', text });
  return parts.length === 1 && parts[0].type === 'text' ? parts[0].text : parts;
}

const apiErrorEl = el("apiError");

// ─────────────────────────────────────────────────
// CLÉS API — 4 fournisseurs
