PROVIDERS.forEach(p => { if (!(p in apiKeysByProvider)) apiKeysByProvider[p] = ""; });

// ─────────────────────────────────────────────────
// SAVE
// ─────────────────────────────────────────────────
function save() {
  try {
    // TOUJOURS sérialiser les chats SANS données binaires volumineuses
    // Ceci évite : blocage du thread principal, localStorage saturé, sync GitHub qui explose
    const lightChats = S.chats.map(chat => ({
