  };
  const [cls, label] = map[provider] || ["badge-openai", provider];
  return `<span class="provider-badge ${cls}">${label}</span>`;
}

// ─────────────────────────────────────────────────
// AFFICHAGE CLÉS API
// ─────────────────────────────────────────────────
function renderApiKeys() {
  const container = el("providerKeys");
  if (!container) return;

  const providerMeta = {
    "ANTHROPIC":    { color:"#c8621a", icon:"🟠", placeholder:"sk-ant-api03-..." },
    "OPENAI":       { color:"#10a37f", icon:"🟢", placeholder:"sk-proj-..." },
    "DEEPSEEK":     { color:"#7b9cf7", icon:"🔵", placeholder:"sk-..." },
    "GOOGLE GEMINI":{ color:"#7baaf7", icon:"🔷", placeholder:"AIza..." },
    "GROQ":         { color:"#f55016", icon:"🔴", placeholder:"gsk_..." }
  };

  container.innerHTML = "";

  PROVIDERS.forEach(name => {
    const val  = apiKeysByProvider[name] || "";
    const meta = providerMeta[name] || { color:"#9ca3af", icon:"⚪", placeholder:"Clé API..." };
    const hasKey = !!val;

    const row = document.createElement("div");
    row.className = "key-row";
    row.innerHTML = `
      <div class="key-header">
        <div class="key-label">${meta.icon} ${name}</div>
        <div class="key-status" id="keyStatus_${name.replace(/\s/g,'_')}">
          <span class="key-dot" style="background:${hasKey ? '#22c55e' : '#6b7280'}"></span>
          <span style="color:${hasKey ? '#22c55e' : '#6b7280'}">${hasKey ? "✓ Configurée" : "Non configurée"}</span>
        </div>
      </div>
      <div class="key-input-row">
        <input class="key-input ${hasKey ? 'has-key' : ''}"
               data-provider="${name}"
               type="password"
               value="${val}"


